import{_ as a,o as r,c as i,a3 as n}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"Tasarım kararları","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/decisions.md","filePath":"architecture/decisions.md"}'),l={name:"architecture/decisions.md"};function t(s,e,o,d,c,m){return r(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="tasarım-kararları" tabindex="-1">Tasarım kararları <a class="header-anchor" href="#tasarım-kararları" aria-label="Permalink to &quot;Tasarım kararları&quot;">​</a></h1><h2 id="neden-accessor-soyutlaması" tabindex="-1">Neden accessor soyutlaması? <a class="header-anchor" href="#neden-accessor-soyutlaması" aria-label="Permalink to &quot;Neden accessor soyutlaması?&quot;">​</a></h2><p>Bir <code>Struct</code> alanının veya <code>CFunction</code> çağrısının, taşınma mekanizmasına göre farklı API&#39;lere bölünmesi kolay görünür; ancak bu, her üst katmanın yerel/uzak ayrımı yapmasına yol açar. Accessor modeli taşıma ayrıntısını altta bırakır ve bileşenleri yeniden kullanılabilir kılar.</p><h2 id="neden-mevcut-sistem-stub-ları" tabindex="-1">Neden mevcut sistem stub&#39;ları? <a class="header-anchor" href="#neden-mevcut-sistem-stub-ları" aria-label="Permalink to &quot;Neden mevcut sistem stub&#39;ları?&quot;">​</a></h2><p>NThread, thread&#39;i yönlendirmek için yüklü sistem modüllerinde küçük talimat dizilerini arar: <code>EB FE</code> (spin), <code>push reg; ret</code>, <code>jmp reg</code>, <code>ret</code> ve <code>add rsp, 0x28; ret</code>. Bu, yönlendirme için büyük bir sabit payload yerleştirme ihtiyacını azaltır; ancak tüm NThread/accessor işlemlerinin hedefte hiç tahsis yapmadığı anlamına gelmez. Örneğin stack argümanları için küçük temizleme stub&#39;ı, accessor middleware&#39;leri için çalışma belleği gerekebilir.</p><h2 id="neden-iki-hook-yaklasımı-var" tabindex="-1">Neden iki hook yaklaşımı var? <a class="header-anchor" href="#neden-iki-hook-yaklasımı-var" aria-label="Permalink to &quot;Neden iki hook yaklaşımı var?&quot;">​</a></h2><p><code>nhook</code>, fonksiyonun ilk iki byte&#39;ını <code>EB FE</code> ile değiştirir; giren thread park edilir ve taşınan prologue host tarafında simüle edilir. Uzaktaki trampoline tahsisini önler fakat polling, instruction simülasyonu ve eşzamanlı thread&#39;ler açısından hassastır.</p><p><code>minhook</code> ise beş byte&#39;lık göreli <code>jmp</code> ve taşınmış talimatlardan oluşan gerçek trampoline kullanır. Daha geleneksel kontrol akışı sağlar; RIP-relative talimatların taşınması ve ±2 GB erişim sınırının relay ile aşılması gerekir.</p><p>Bu seçenekler birbirinin genel amaçlı yerine geçeni değildir; hedef fonksiyonun prologue&#39;u, erişim yolu ve kabul edilen risk belirleyicidir.</p>',9)])])}const h=a(l,[["render",t]]);export{u as __pageData,h as default};
